using System.Threading;

public class Store
{
    private readonly ReaderWriterLock _lock = new ReaderWriterLock();

    public void Append()
    {
        _lock.AcquireWriterLock(1000);
        try
        {
            Write();
        }
        finally
        {
            _lock.ReleaseWriterLock();
        }
    }

    private void Write()
    {
    }
}
